+using System.Text.RegularExpressions;
+
+namespace DocSummary.Services;
+
+/// <summary>
+/// A simple extractive summarizer that scores sentences by word frequency
+/// and returns the top-ranked ones in their original order.
+/// </summary>
+public partial class ExtractiveSummarizer : IDocumentSummarizer
+{
+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
+        "in", "on", "at", "to", "for", "of", "with", "by", "it", "this",
+        "that", "from", "as", "be", "has", "had", "have", "not", "no",
+        "do", "does", "did", "will", "would", "could", "should", "may",
+        "can", "its", "they", "them", "their", "he", "she", "his", "her",
+        "we", "our", "you", "your", "i", "me", "my", "so", "if", "then",
+        "than", "when", "what", "which", "who", "how", "all", "each",
+        "been", "being", "about", "into", "over", "after", "before"
+    };
+
+    public string Summarize(string documentText, int maxSentences)
+    {
+        var sentences = SplitSentences(documentText);
+
+        if (sentences.Count <= maxSentences)
+            return string.Join(" ", sentences);
+
+        // Build word frequency map (excluding stop words)
+        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in Tokenize(sentence))
+            {
+                if (!StopWords.Contains(word) && word.Length > 1)
+                    wordFrequency[word] = wordFrequency.GetValueOrDefault(word) + 1;
+            }
+        }
+
+        // Score each sentence by the sum of its word frequencies
+        var scored = sentences
+            .Select((text, index) => new
+            {
+                Text = text,
+                Index = index,
+                Score = Tokenize(text)
+                    .Where(w => wordFrequency.ContainsKey(w))
+                    .Sum(w => wordFrequency[w])
+            })
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .OrderBy(s => s.Index) // preserve original order
+            .Select(s => s.Text);
+
+        return string.Join(" ", scored);
+    }
+
+    private static List<string> SplitSentences(string text)
+    {
+        // Split on sentence-ending punctuation followed by whitespace or end-of-string
+        var parts = SentenceRegex().Split(text.Trim());
+        return parts
+            .Select(s => s.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static IEnumerable<string> Tokenize(string sentence)
+    {
+        return WordRegex().Matches(sentence).Select(m => m.Value.ToLowerInvariant());
+    }
+
+    [GeneratedRegex(@"(?<=[.!?])\s+")]
+    private static partial Regex SentenceRegex();
+
+    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
+    private static partial Regex WordRegex();
+}
